/**
 * @param {Point[]} points
 * @param {number[]} target
 * @return {number}
 */
function solve(points, target) {
    /**
     * Helper to convert a 3D point array to a string for easy set storage.
     * @param {Point} p
     * @returns {string}
     */
    const pointToString = (p) => `${p[0]},${p[1]},${p[2]}`;

    // Check for k=0
    const initialPointSet = new Set(points.map(pointToString));
    const targetStr = pointToString(target);
    if (initialPointSet.has(targetStr)) {
        return 0;
    }

    // Current set of all points available up to the previous generation
    // Start with points from generation 0.
    let currentPoints = [...points];
    let k = 0;

    // Safety break: maximum number of generations or if no new points are generated
    // Given the constraints (coords <= 6), the search space is small, but we need a termination condition.
    // Since the number of points grows, we rely on finding the target or generating no new points.
    const MAX_ITERATIONS = 100; 

    while (k < MAX_ITERATIONS) {
        k++;
        const newPoints = new Set();
        const currentPointsCount = currentPoints.length;

        // If fewer than 2 unique points exist, no new pairs can be formed.
        if (currentPointsCount < 2) {
            return -1;
        }

        // Use the set of unique coordinates present in currentPoints to ensure we only pair distinct coordinates.
        // Note: The problem states: "select two different points a and b" and "two different (x, y, z) coordinates".
        // We must use all points from currentPoints, but only pair those with distinct coordinates.

        // Get unique coordinates present in the current pool of points.
        const uniqueCoords = Array.from(new Set(currentPoints.map(pointToString))).map(s => s.split(',').map(Number));

        const uniquePoints = uniqueCoords;
        const uniqueCount = uniquePoints.length;

        let pointsGeneratedInThisStep = false;

        // Iterate over all pairs of unique coordinates (which represent distinct points based on coordinate values)
        for (let i = 0; i < uniqueCount; i++) {
            for (let j = i + 1; j < uniqueCount; j++) {
                const p1 = uniquePoints[i];
                const p2 = uniquePoints[j];

                // Calculate the midpoint c = [floor((x1 + x2) / 2), ...]
                const c = [
                    Math.floor((p1[0] + p2[0]) / 2),
                    Math.floor((p1[1] + p2[1]) / 2),
                    Math.floor((p1[2] + p2[2]) / 2)
                ];

                const cStr = pointToString(c);

                // Add to the new points set if it's not already in the set of points generated in this step.
                if (!newPoints.has(cStr)) {
                    newPoints.add(cStr);
                    pointsGeneratedInThisStep = true;
                }
            }
        }

        // Convert generated strings back to points and add them to the pool
        const generatedPointsArray = Array.from(newPoints).map(s => s.split(',').map(Number));

        // Check if the target was generated in this step (Generation k)
        for (const newP of generatedPointsArray) {
            if (pointToString(newP) === targetStr) {
                return k;
            }
        }

        // Update currentPoints: Add all newly generated unique points
        // We must ensure we don't add points that were already present in previous generations (i.e., in the original 'points' or generated in earlier steps).
        const currentPointSet = new Set(currentPoints.map(pointToString));

        for (const newP of generatedPointsArray) {
            if (!currentPointSet.has(pointToString(newP))) {
                currentPoints.push(newP);
                currentPointSet.add(pointToString(newP));
            }
        }

        // If no new unique points were generated, we are stuck.
        if (!pointsGeneratedInThisStep) {
             // This check might be slightly redundant if we check currentPointsCount < 2, 
             // but it correctly handles cases where all possible pairs already yield existing points.
             return -1;
        }
    }

    // If the loop terminates due to MAX_ITERATIONS (shouldn't happen given problem constraints if a solution exists)
    return -1;
}

